/* istanbul ignore file */
import { Component, Host, h, Element, Prop, Listen, Event, EventEmitter } from '@stencil/core';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';

import { IMenuItem } from '../mx-nav/mx-nav.model';

@Component({
  tag: 'mx-header-nav',
  styleUrl: 'mx-header-nav.css'
})
export class HeaderNav {
  @Element() hostEle: HTMLMxHeaderNavElement;

  /** Sets the array of menu data. */
  @Prop() readonly data: IMenuItem[];
  /** Sets the number of columns. */
  @Prop() readonly columns: number;

  /** Sets the function that triggers when an item is clicked. */
  @Event() headerMenuItemClick: EventEmitter;

  private readonly activeClass = 'mx-active';
  private menuColumns: number[] = [];

  componentWillLoad() {
    this.menuColumns = Array.from({ length: this.columns }, (_, i) => i + 1);
  }

  @Listen('click', { target: 'document', capture: true })
  handleOutsideClick(ev) {
    // If the item clicked does not have the mx-menu-item-container as a parent then we clicked outside the menu
    const hasMenuItemParent = ev.target.closest('.mx-menu-item-container') != null;

    // Clicked outside the menu?
    if (!hasMenuItemParent || ev.target.classList.contains("mx-menu-item-no-children")) {
      // close Active submenu.
      const openMenuContainer = document.getElementsByClassName('mx-menu-item-container mx-active')[0];


      if (!isNullOrUndefined(openMenuContainer)) {
        openMenuContainer.classList.remove(this.activeClass);
      }
    }
  }

  private readonly activateLink = (cls: string) => (event: MouseEvent) => {

    event.preventDefault();

    const ele = this.hostEle.querySelector(cls);

    this.hostEle.querySelectorAll(`li.${this.activeClass}:not(${cls})`).forEach((x) => {
      x.classList.remove(this.activeClass);
    });

    if (ele.classList.contains(this.activeClass)) {
      ele.classList.remove(this.activeClass);
    } else {
      ele.classList.add(this.activeClass);
    }
  };

  private readonly menuClick = (item: IMenuItem) => (event) => {
    const realItem = item || event.detail;
    this.headerMenuItemClick.emit(realItem);
  };

  render() {
    return (
      <Host>
        <nav class='bg-brand-800 flex'>
          <ul class='flex list-reset'>
            {this.data?.map((menuItem: IMenuItem, i) => {
              return (
                <li
                  class={{
                    "heading-s self-stretch flex mx-menu-item-container pr-7": true,
                    relative: menuItem.children?.length > 0,
                    [`linkItem${i}`]: true
                  }}>
                  {menuItem.children?.length > 0 ? (
                    <kds-link
                      implied
                      inverse
                      class='mx-menu-item-link'
                      size='l'
                      onClick={this.activateLink(`.linkItem${i}`)}>
                      {menuItem.label}
                      <kds-icon-chevron-down size='s' class='mx-hide_active mx-chevron'></kds-icon-chevron-down>
                      <kds-icon-chevron-up size='s' class='mx-show_active mx-chevron'></kds-icon-chevron-up>
                    </kds-link>
                  ) : (
                    <kds-link inverse implied size='l' class='mx-menu-item-link mx-menu-item-no-children'
                      linkClass='mx-menu-item-no-children' onClick={this.menuClick(menuItem)}>
                      {menuItem.label}
                    </kds-link>
                  )}
                  {menuItem.children?.length > 0 && (
                    <div class='mx-sub-menu absolute text-left left-0'>
                      <div class='mx-arrow-up-shadow absolute overflow-hidden ml-auto'></div>
                      <div class='mx-sub-container shadow-2 px-16 py-16 rounded-medium flex flex-row'>
                        {this.menuColumns.map((x: any) => {
                          return (
                            <div
                              class={{
                                "inline-block align-top": true,
                                "mr-24": menuItem.children.length >= this.columns && x !== this.columns
                              }}>
                              <mx-sub-menu
                                onSubMenuClickHandler={this.menuClick(null)}
                                columnNum={x}
                                columns={this.columns}
                                subMenu={menuItem.children}></mx-sub-menu>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </li>
              );
            })}
          </ul>
        </nav>
      </Host>
    );
  }
}
